class RemediationTracker:
    """
    Tracks all mock-audit findings through remediation to verified closure.
    Produces a readiness score and escalation alerts.
    """
    SEVERITY_WEIGHT = {
        FindingSeverity.CRITICAL: 40,
        FindingSeverity.HIGH:     20,
        FindingSeverity.MODERATE: 10,
        FindingSeverity.LOW:       5,
    }

    def __init__(self, findings: list[MockAuditFinding]):
        self._findings = findings

    def readiness_score(self) -> float:
        """
        100% means all findings verified closed.
        Weighted by severity — a single open CRITICAL caps the score below 60%.
        """
        total_weight = sum(self.SEVERITY_WEIGHT[f.severity] for f in self._findings)
        if total_weight == 0:
            return 100.0
        closed_weight = sum(
            self.SEVERITY_WEIGHT[f.severity]
            for f in self._findings
            if f.status in (FindingStatus.VERIFIED, FindingStatus.ACCEPTED)
        )
        return round((closed_weight / total_weight) * 100, 1)

    def overdue_findings(self) -> list[MockAuditFinding]:
        return [f for f in self._findings if f.is_overdue()]

    def open_criticals(self) -> list[MockAuditFinding]:
        return [f for f in self._findings
                if f.severity == FindingSeverity.CRITICAL
                and f.status not in (FindingStatus.VERIFIED, FindingStatus.ACCEPTED)]

    def summary(self) -> dict:
        by_status: dict[str, int] = {}
        for f in self._findings:
            by_status[f.status.value] = by_status.get(f.status.value, 0) + 1
        return {
            "total":           len(self._findings),
            "by_status":       by_status,
            "readiness_score": self.readiness_score(),
            "overdue":         len(self.overdue_findings()),
            "open_criticals":  len(self.open_criticals()),
            "repeat_findings": sum(1 for f in self._findings if f.repeat),
        }

